
.layout {
  display: grid;
  gap: var(--zg-space-2);
}

.section-wide {
  width: 100%;
}

.category-grid {
  display: grid;
  gap: var(--zg-space-2);
  grid-template-columns: repeat(auto-fit, minmax(min(100%, 16rem), 1fr));
  grid-auto-flow: dense;
  align-items: start;
}

.detail-grid {
  display: grid;
  gap: var(--zg-space-2);
}

.row span,
.meter-meta,
.slot small,
.summary-row span,
.summary-divider,
.summary-change span {
  font-family: "IBM Plex Mono", "Courier New", monospace;
}

.rows,
.list,
.meters {
  display: grid;
  gap: var(--zg-space-2);
}

.summary-strip {
  display: flex;
  flex-wrap: wrap;
  align-items: baseline;
  gap: var(--zg-space-1) var(--zg-space-2);
}

.summary-row {
  display: inline-flex;
  align-items: baseline;
  gap: var(--zg-space-1);
  min-width: 0;
}

.summary-divider {
  color: rgba(200, 168, 74, 0.52);
  font-size: var(--zg-fs-xs);
}

.summary-change {
  margin-top: var(--zg-space-3);
  display: grid;
  gap: var(--zg-space-1);
}

.compact {
  margin-top: var(--zg-space-3);
}

.row {
  display: grid;
  gap: var(--zg-space-1);
}

.row span,
.meter-meta,
.slot small,
.summary-row span,
.summary-change span {
  font-size: var(--zg-fs-2xs);
  color: var(--zg-muted);
  letter-spacing: 0.12em;
}

.row strong,
.summary-row strong,
.summary-change strong {
  font-size: var(--zg-fs-md);
  line-height: 1.55;
}

.slot-grid {
  display: grid;
  gap: var(--zg-space-2);
  grid-template-columns: repeat(auto-fit, minmax(6.5rem, 1fr));
  grid-auto-flow: dense;
  align-items: start;
}

.slot {
  position: relative;
  padding: var(--zg-space-2) var(--zg-space-3) calc(var(--zg-space-2) - 0.05rem) var(--zg-space-4);
  border-radius: 3px;
  border: 1px solid rgba(138, 122, 80, 0.2);
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.04), transparent 48%),
    linear-gradient(90deg, rgba(255, 255, 255, 0.012) 1px, transparent 1px),
    rgba(8, 14, 8, 0.72);
  background-size: auto, 16px 16px, auto;
  display: grid;
  gap: var(--zg-space-1);
  box-shadow: inset 0 0 0 1px rgba(255, 255, 255, 0.018);

  &::before {
    content: "";
    position: absolute;
    left: 0;
    top: 8px;
    bottom: 8px;
    width: 2px;
    border-radius: 999px;
    background: currentColor;
    opacity: 0.76;
  }

  &.weapon {
    color: #8fa8c3;
    border-color: rgba(122, 154, 190, 0.28);
    background-color: rgba(23, 35, 48, 0.58);
  }

  &.medical {
    color: #b56a6a;
    border-color: rgba(181, 106, 106, 0.28);
    background-color: rgba(52, 24, 24, 0.58);
  }

  &.ration {
    color: #79956f;
    border-color: rgba(121, 149, 111, 0.28);
    background-color: rgba(24, 39, 22, 0.58);
  }

  &.artifact {
    color: #8f79c9;
    border-color: rgba(143, 121, 201, 0.28);
    background-color: rgba(34, 26, 52, 0.58);
  }

  &.intel {
    color: #d1b46b;
    border-color: rgba(209, 180, 107, 0.28);
    background-color: rgba(58, 45, 18, 0.58);
  }
}

.slot strong {
  color: var(--zg-text);
  font-size: var(--zg-fs-md);
  line-height: 1.28;
}

.slot span {
  color: var(--zg-soft);
  font-size: var(--zg-fs-xs);
  line-height: 1.45;
}

.list-card {
  padding: var(--zg-space-4);
  border-radius: 4px;
  border: 1px solid rgba(138, 122, 80, 0.18);
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.04), transparent 55%),
    rgba(255, 255, 255, 0.025);

  strong {
    display: block;
    font-size: var(--zg-fs-lg);
    color: var(--zg-text);
  }
}

.meter {
  display: grid;
  gap: var(--zg-space-1);
}

.meter-meta {
  display: flex;
  justify-content: space-between;
  gap: var(--zg-space-2);
}

.meter-track {
  height: 8px;
  border-radius: 999px;
  overflow: hidden;
  background: rgba(255, 255, 255, 0.08);
}

.meter-fill {
  display: block;
  height: 100%;
  border-radius: 999px;

  &.blue {
    background: linear-gradient(90deg, #4f74a4, var(--zg-blue));
  }

  &.gold {
    background: linear-gradient(90deg, #856834, var(--zg-gold));
  }
}

.empty {
  padding: var(--zg-space-4);
  border-radius: 4px;
  border: 1px dashed rgba(138, 122, 80, 0.28);
  background: rgba(255, 255, 255, 0.02);
  color: var(--zg-muted);
  line-height: 1.7;
}

@media (max-width: 560px) {
  .summary-strip {
    gap: var(--zg-space-1) var(--zg-space-2);
  }

  .summary-row {
    gap: var(--zg-space-1);
  }

  .slot-grid {
    grid-template-columns: repeat(auto-fit, minmax(5.75rem, 1fr));
  }

  .slot {
    padding: var(--zg-space-2) var(--zg-space-2) calc(var(--zg-space-2) - 0.05rem) var(--zg-space-3);
  }
}
