
.grid {
  display: grid;
  gap: var(--zg-space-2);
}

.row span,
.meta,
.archive-card small {
  font-family: "IBM Plex Mono", "Courier New", monospace;
}

h2 {
  font-size: var(--zg-fs-xl);
  line-height: 1.1;
}

.rows {
  display: grid;
  gap: var(--zg-space-2);
}

.row {
  display: grid;
  gap: var(--zg-space-1);
}

.row span,
.meta {
  font-size: var(--zg-fs-2xs);
  color: var(--zg-muted);
  letter-spacing: 0.12em;
}

.row strong {
  font-size: var(--zg-fs-md);
  line-height: 1.55;
}

.meter {
  margin-top: var(--zg-space-3);
}

.meta {
  display: flex;
  justify-content: space-between;
  gap: var(--zg-space-2);
  margin-bottom: var(--zg-space-1);
}

.track {
  height: 8px;
  border-radius: 999px;
  overflow: hidden;
  background: rgba(255, 255, 255, 0.08);
}

.fill {
  display: block;
  height: 100%;
  border-radius: 999px;
  background: linear-gradient(90deg, var(--zg-violet), var(--zg-pink));
}

.archives {
  display: grid;
  gap: var(--zg-space-2);
  margin-top: var(--zg-space-3);
  grid-template-columns: repeat(auto-fit, minmax(min(100%, 15.5rem), 1fr));
  grid-auto-flow: dense;
  align-items: start;
}

.compact {
  margin-top: var(--zg-space-3);
}

.archive-card {
  padding: var(--zg-space-3) var(--zg-space-4);
  border-radius: 3px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(138, 122, 80, 0.16);

  strong {
    display: block;
    font-size: var(--zg-fs-lg);
  }

  small {
    display: block;
    margin-top: var(--zg-space-1);
    color: var(--zg-soft);
    font-size: var(--zg-fs-2xs);
  }
}

.faction-groups {
  display: grid;
  gap: var(--zg-space-3);
}

.faction-group {
  display: grid;
  gap: var(--zg-space-2);
}

.group-title {
  font-family: "IBM Plex Mono", "Courier New", monospace;
  font-size: var(--zg-fs-2xs);
  color: var(--zg-muted);
  letter-spacing: 0.12em;

  &.warn {
    color: #f2b0b0;
  }
}

.faction-list {
  display: grid;
  gap: var(--zg-space-2);
  grid-template-columns: repeat(auto-fit, minmax(min(100%, 14rem), 1fr));
  grid-auto-flow: dense;
  align-items: start;
}

.faction-card {
  padding: var(--zg-space-3) var(--zg-space-4);
  border-radius: 3px;
  border: 1px solid rgba(138, 122, 80, 0.18);
  background: rgba(255, 255, 255, 0.03);

  &.ally {
    border-color: rgba(95, 141, 180, 0.2);
  }

  &.enemy {
    border-color: rgba(200, 96, 96, 0.22);
  }
}

.faction-head {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  gap: var(--zg-space-2);
  margin-bottom: var(--zg-space-2);

  strong {
    font-size: var(--zg-fs-lg);
    color: var(--zg-text);
  }

  small {
    font-family: "IBM Plex Mono", "Courier New", monospace;
    font-size: var(--zg-fs-2xs);
    color: var(--zg-soft);
    letter-spacing: 0.12em;
  }
}

.fill.green {
  background: linear-gradient(90deg, #55784f, var(--zg-green));
}

.fill.red {
  background: linear-gradient(90deg, #8a4141, var(--zg-red));
}

.empty {
  padding: var(--zg-space-4);
  border-radius: 4px;
  border: 1px dashed rgba(138, 122, 80, 0.28);
  color: var(--zg-muted);
}
