
.grid {
  display: grid;
  gap: var(--zg-space-2);
}

.row span {
  font-family: "IBM Plex Mono", "Courier New", monospace;
  font-size: var(--zg-fs-2xs);
  color: var(--zg-muted);
  letter-spacing: 0.12em;
}

.rows {
  display: grid;
  gap: var(--zg-space-2);
}

.row {
  display: grid;
  gap: var(--zg-space-1);
}

.row strong {
  font-size: var(--zg-fs-md);
  line-height: 1.55;
}

.empty {
  padding: var(--zg-space-4);
  border-radius: 4px;
  border: 1px dashed rgba(138, 122, 80, 0.28);
  color: var(--zg-muted);
}
