
.layout {
  display: grid;
  gap: var(--zg-space-2);
}

.section-wide {
  width: 100%;
}

.card-grid {
  display: grid;
  gap: var(--zg-space-2);
  grid-template-columns: repeat(auto-fit, minmax(min(100%, 16rem), 1fr));
  grid-auto-flow: dense;
  align-items: start;
}

.row span,
.meter-meta {
  font-family: "IBM Plex Mono", "Courier New", monospace;
}

.meters,
.rows {
  display: grid;
  gap: var(--zg-space-2);
}

.meter {
  display: grid;
  gap: var(--zg-space-1);
}

.meter-meta {
  display: flex;
  justify-content: space-between;
  gap: var(--zg-space-2);
  font-size: var(--zg-fs-2xs);
  color: rgba(226, 220, 204, 0.74);
}

.meter-track {
  height: 8px;
  border-radius: 999px;
  overflow: hidden;
  background: rgba(255, 255, 255, 0.08);
}

.meter-fill {
  display: block;
  height: 100%;
  border-radius: 999px;

  &.blue {
    background: linear-gradient(90deg, #4f74a4, var(--zg-blue));
  }

  &.green {
    background: linear-gradient(90deg, #55784f, var(--zg-green));
  }

  &.red {
    background: linear-gradient(90deg, #8a4141, var(--zg-red));
  }

  &.gold {
    background: linear-gradient(90deg, #856834, var(--zg-gold));
  }
}

.row {
  display: grid;
  gap: var(--zg-space-1);
}

.row span {
  display: inline-flex;
  justify-self: start;
  align-items: center;
  width: fit-content;
  padding: 1px 6px;
  border-radius: 2px;
  border: 1px solid rgba(138, 122, 80, 0.18);
  background: rgba(9, 15, 10, 0.88);
  font-size: var(--zg-fs-2xs);
  color: rgba(226, 220, 204, 0.82);
  letter-spacing: 0.12em;
}

.row strong {
  font-size: var(--zg-fs-md);
  line-height: 1.55;
}

.empty {
  padding: 12px;
  border-radius: 4px;
  border: 1px dashed rgba(138, 122, 80, 0.28);
  color: var(--zg-muted);
}
