
.grid {
  display: grid;
  gap: var(--zg-space-2);
}

.row span,
.meta {
  font-family: "IBM Plex Mono", "Courier New", monospace;
}

.desc {
  color: var(--zg-soft);
  font-size: var(--zg-fs-sm);
  line-height: 1.58;
}

.summary-block {
  margin-top: var(--zg-space-3);
  display: grid;
  gap: var(--zg-space-1);

  span,
  strong {
    font-family: "IBM Plex Mono", "Courier New", monospace;
  }

  span {
    font-size: var(--zg-fs-2xs);
    color: var(--zg-muted);
    letter-spacing: 0.12em;
  }

  strong {
    color: rgba(240, 216, 232, 0.92);
    font-size: var(--zg-fs-sm);
    line-height: 1.56;
    font-weight: 600;
  }
}

.meters,
.rows {
  display: grid;
  gap: var(--zg-space-2);
  margin-top: var(--zg-space-3);
}

.meter {
  margin-top: var(--zg-space-3);
}

.meter-block {
  margin-top: 0;
}

.phase-summary {
  margin-top: var(--zg-space-3);
  display: inline-flex;
  align-items: baseline;
  gap: var(--zg-space-3);
  flex-wrap: wrap;

  span,
  strong {
    font-family: "IBM Plex Mono", "Courier New", monospace;
  }

  span {
    font-size: var(--zg-fs-2xs);
    color: var(--zg-muted);
    letter-spacing: 0.12em;
  }

  strong {
    font-size: var(--zg-fs-lg);
    color: var(--zg-text);
  }
}

.meta {
  display: flex;
  justify-content: space-between;
  gap: var(--zg-space-2);
  margin-bottom: var(--zg-space-1);
  font-size: var(--zg-fs-2xs);
  color: var(--zg-muted);
}

.track {
  height: 8px;
  border-radius: 999px;
  overflow: hidden;
  background: rgba(255, 255, 255, 0.08);
}

.fill {
  display: block;
  height: 100%;
  border-radius: 999px;
  background: linear-gradient(90deg, var(--zg-violet), var(--zg-pink), #f0d8e8);

  &.violet {
    background: linear-gradient(90deg, #8371ca, var(--zg-violet));
  }

  &.pink {
    background: linear-gradient(90deg, #d283b9, var(--zg-pink));
  }

  &.rose {
    background: linear-gradient(90deg, #e0889d, #ffb8c8);
  }

  &.romance {
    background: linear-gradient(90deg, #ac7ae6, #f2a8db, #f5d6ea);
  }
}

.row {
  display: grid;
  gap: var(--zg-space-1);
}

.row span {
  font-size: var(--zg-fs-2xs);
  color: var(--zg-muted);
  letter-spacing: 0.12em;
}

.row strong {
  font-size: var(--zg-fs-md);
  line-height: 1.55;
}
