
.grid {
  display: grid;
  gap: var(--zg-space-2);
}

.row span,
.meter-meta,
small {
  font-family: "IBM Plex Mono", "Courier New", monospace;
}

.rows,
.list,
.meters {
  display: grid;
  gap: var(--zg-space-2);
}

.list {
  grid-template-columns: repeat(auto-fit, minmax(min(100%, 16rem), 1fr));
  grid-auto-flow: dense;
  align-items: start;
}

.compact {
  margin-top: var(--zg-space-3);
}

.entry-card {
  padding: var(--zg-space-4);
  border-radius: 3px;
  border: 1px solid rgba(138, 122, 80, 0.16);
  background: rgba(255, 255, 255, 0.03);

  strong {
    display: block;
    font-size: var(--zg-fs-lg);
  }

  small {
    display: block;
    margin-top: var(--zg-space-1);
    color: var(--zg-soft);
    font-size: var(--zg-fs-xs);
  }

  &.danger {
    border-color: rgba(200, 96, 96, 0.24);
  }
}

.row {
  display: grid;
  gap: var(--zg-space-1);
}

.row span,
.meter-meta {
  font-size: var(--zg-fs-2xs);
  color: var(--zg-muted);
  letter-spacing: 0.12em;
}

.row strong {
  font-size: var(--zg-fs-md);
  line-height: 1.55;
}

.meter {
  display: grid;
  gap: var(--zg-space-1);
}

.meter-meta {
  display: flex;
  justify-content: space-between;
  gap: var(--zg-space-2);
}

.meter-track {
  height: 8px;
  border-radius: 999px;
  overflow: hidden;
  background: rgba(255, 255, 255, 0.08);
}

.meter-fill {
  display: block;
  height: 100%;
  border-radius: 999px;

  &.red {
    background: linear-gradient(90deg, #8a4141, var(--zg-red));
  }

  &.green {
    background: linear-gradient(90deg, #55784f, var(--zg-green));
  }
}

.empty {
  padding: var(--zg-space-4);
  border-radius: 4px;
  border: 1px dashed rgba(138, 122, 80, 0.28);
  color: var(--zg-muted);
}
